CREATE TABLE IF NOT EXISTS "DocumentDemande" ("id" TEXT NOT NULL, "demandeId" TEXT NOT NULL, "nom" TEXT NOT NULL, "type" TEXT NOT NULL, "taille" INTEGER NOT NULL, "contenu" BYTEA NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "DocumentDemande_pkey" PRIMARY KEY ("id"), CONSTRAINT "DocumentDemande_demandeId_fkey" FOREIGN KEY ("demandeId") REFERENCES "Demande"("id") ON DELETE CASCADE ON UPDATE CASCADE);
